	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Generate a secure random state token to prevent CSRF attacks
	stateBytes := make([]byte, 16)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate state token: %w", err)
	}
	state := hex.EncodeToString(stateBytes)

	// 2. Store the state and the intended redirect path in the session cookie
	// In a real application, you might use a session store (like Redis or a signed cookie).
	// Here, we will simply append these values to the cookie's Value for demonstration purposes.
	// Note: Cookie values should be URL-encoded to handle special characters.

	// Construct new data string (simple format: key=value&key2=value2)
	newData := fmt.Sprintf("oauth_state=%s&redirect_path=%s", state, url.QueryEscape(redirectPath))

	// Combine with existing data if necessary, or just overwrite for this specific auth flow
	// For simplicity in this context, we set the cookie value to the new data.
	// In production, you would likely manage a session map.
	cookieValue := newData

	// Create the cookie
	cookie := &http.Cookie{
		Name:     "oauth_session",
		Value:    cookieValue,
		Path:     "/",
		HttpOnly: true,
		Secure:   true, // Requires HTTPS
		SameSite: http.SameSiteLaxMode,
	}
	http.SetCookie(w, cookie)

	// 3. Generate the authorization URL using the oauth2 package
	// We pass the generated state and the scopes defined in the config.
	authURL := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOnline)

	return authURL, nil
}

func main() {
	// Example usage
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		// Retrieve existing cookie if any
		session, _ := r.Cookie("oauth_session")

		// Define where the user should land after successful auth (callback logic will use this)
		redirectPath := "/dashboard"

		// Generate the URL
		authURL, err := GenerateAuthURL(redirectPath, session, w, r)
		if err != nil {
			http.Error(w, "Failed to generate auth URL", http.StatusInternalServerError)
			return
		}

		// Redirect the user to the provider
		http.Redirect(w, r, authURL, http.StatusFound)
	})

	http.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
		// This is where the provider redirects the user back to
		// Logic to exchange code for token would go here
		w.Write([]byte("Callback received. (Token exchange logic omitted for brevity)"))
	})

	fmt.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

