func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a random state token to prevent CSRF attacks
	state, err := generateStateToken()
	if err != nil {
		return "", fmt.Errorf("failed to generate state token: %w", err)
	}

	// Store the intended redirect path in the state to use after callback
	// In a real application, you might want to use a more secure storage mechanism
	// or include this in the state token generation logic.
	// Here we encode it into the state parameter itself for simplicity, 
	// but typically you would store this in a session or cache.

	// Create a state payload containing the redirect path and a timestamp
	statePayload := map[string]interface{}{
		"redirect": redirectPath,
		"time":     time.Now().Unix(),
	}

	// Marshal the payload
	payloadBytes, err := json.Marshal(statePayload)
	if err != nil {
		return "", fmt.Errorf("failed to marshal state payload: %w", err)
	}

	// Encode payload to base64
	stateData := base64.URLEncoding.EncodeToString(payloadBytes)

	// Combine random token with data (or just use data if random enough, 
	// but here we append the random token for extra security)
	fullState := state + "." + stateData

	// Set a secure cookie with the state token
	// Note: In production, ensure the cookie is HttpOnly, Secure, and SameSite=Strict/Lax
	cookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    fullState,
		Path:     "/",
		HttpOnly: true,
		Secure:   true, // Requires HTTPS
		SameSite: http.SameSiteLaxMode,
		MaxAge:   300, // 5 minutes expiration
	}
	http.SetCookie(w, cookie)

	// If a session cookie is provided, we might want to associate it with the request
	// but the standard oauth2 package handles the state validation internally 
	// or we handle it in the callback handler.
	// Here we simply return the AuthCodeURL.

	// Generate the authorization URL
	authURL := OAuthConfig.AuthCodeURL(fullState, oauth2.AccessTypeOffline)

	return authURL, nil
}

